--
-- Name: update_tag_count(); Type: FUNCTION; Schema: public; Owner: neondb_owner
--

CREATE FUNCTION public.update_tag_count() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
      BEGIN
        IF TG_OP = 'INSERT' THEN
          UPDATE public.tags SET count = count + 1 WHERE id = NEW.tag_id;
        ELSIF TG_OP = 'DELETE' THEN
          UPDATE public.tags SET count = count - 1 WHERE id = OLD.tag_id;
        END IF;
        RETURN NULL;
      END;
      $$;


ALTER FUNCTION public.update_tag_count() OWNER TO neondb_owner;

